SELECT COALESCE(SUM(CASE hh WHEN '00' THEN 1 ELSE 0 END), 0) AS "00" , COALESCE(SUM(CASE hh WHEN '01' THEN 1 ELSE 0 END), 0) AS "01" , COALESCE(SUM(CASE hh WHEN '02' THEN 1 ELSE 0 END), 0) AS "02" , COALESCE(SUM(CASE hh WHEN '03' THEN 1 ELSE 0 END), 0) AS "03" , COALESCE(SUM(CASE hh WHEN '04' THEN 1 ELSE 0 END), 0) AS "04" , COALESCE(SUM(CASE hh WHEN '05' THEN 1 ELSE 0 END), 0) AS "05" , COALESCE(SUM(CASE hh WHEN '06' THEN 1 ELSE 0 END), 0) AS "06" , COALESCE(SUM(CASE hh WHEN '07' THEN 1 ELSE 0 END), 0) AS "07" , COALESCE(SUM(CASE hh WHEN '08' THEN 1 ELSE 0 END), 0) AS "08" , COALESCE(SUM(CASE hh WHEN '09' THEN 1 ELSE 0 END), 0) AS "09" , COALESCE(SUM(CASE hh WHEN '10' THEN 1 ELSE 0 END), 0) AS "10" , COALESCE(SUM(CASE hh WHEN '11' THEN 1 ELSE 0 END), 0) AS "11" , COALESCE(SUM(CASE hh WHEN '12' THEN 1 ELSE 0 END), 0) AS "12" , COALESCE(SUM(CASE hh WHEN '13' THEN 1 ELSE 0 END), 0) AS "13" , COALESCE(SUM(CASE hh WHEN '14' THEN 1 ELSE 0 END), 0) AS "14" , COALESCE(SUM(CASE hh WHEN '15' THEN 1 ELSE 0 END), 0) AS "15" , COALESCE(SUM(CASE hh WHEN '16' THEN 1 ELSE 0 END), 0) AS "16" , COALESCE(SUM(CASE hh WHEN '17' THEN 1 ELSE 0 END), 0) AS "17" , COALESCE(SUM(CASE hh WHEN '18' THEN 1 ELSE 0 END), 0) AS "18" , COALESCE(SUM(CASE hh WHEN '19' THEN 1 ELSE 0 END), 0) AS "19" , COALESCE(SUM(CASE hh WHEN '20' THEN 1 ELSE 0 END), 0) AS "20" , COALESCE(SUM(CASE hh WHEN '21' THEN 1 ELSE 0 END), 0) AS "21" , COALESCE(SUM(CASE hh WHEN '22' THEN 1 ELSE 0 END), 0) AS "22" , COALESCE(SUM(CASE hh WHEN '23' THEN 1 ELSE 0 END), 0) AS "23" FROM ( SELECT mgr_seq , usr_id , use_time , substring(use_time, 9, 2) AS hh FROM xeus.mt_aces_log) AS r
usr_id is not null
AND use_time >= #{startDat}
